 257→router.get('/getNotifications', requireAuth, async(req, res) =>{
 258→    const {before, limit} = req.query;
 259→    const userId = req.userId;
 260→
 261→    // Fetch a generous amount from both tables, then merge and paginate
 262→    const fetchLimit = parseInt(limit) + 1;
 263→
 264→    let journalQuery = supabase
 265→    .from('notifications')
 266→    .select(
 267→        `*,
 268→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 269→        users!sender_id(name, user_email, image_url, id, badge)
 270→        `
 271→    )
 272→    .eq('receiver_id', userId)
 273→    .order('created_at', {ascending: false})
 274→    .order('id', {ascending: false})
 275→    .limit(fetchLimit)
 276→
 277→    let opinionQuery = supabase
 278→    .from('notification_opinions')
 279→    .select(
 280→        `*,
 281→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 282→        users!sender_id(name, user_email, image_url, id, badge)
 283→        `
 284→    )
 285→    .eq('receiver_id', userId)
 286→    .order('created_at', {ascending: false})
 287→    .order('id', {ascending: false})
 288→    .limit(fetchLimit)
 289→
 290→    if(before){
 291→        journalQuery = journalQuery.lt('created_at', before);
 292→        opinionQuery = opinionQuery.lt('created_at', before);
 293→    }
 294→
 295→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 296→
 297→    if(journalResult.error){
 298→        console.error('error while fetching data from notification table:', journalResult.error);
 299→        return res.status(500).json({error: 'error fetching data from notification table'});
 300→    }
 301→    if(opinionResult.error){
 302→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 303→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 304→    }
 305→
 306→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 307→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 308→
 309→    // Merge and sort by created_at descending
 310→    const merged = [...journalNotifs, ...opinionNotifs]
 311→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 312→
 313→    // Likes/bookmarks lookup only for journal notifications
 314→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 315→
 316→    let hasLikedResult = [];
 317→    let hasBookMarkedResult = [];
 318→    if(journalIds.length > 0){
 319→        const [hasLiked, hasBookMarked] = await Promise.all([
 320→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 321→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 322→        ]);
 323→
 324→        if(hasLiked.error || hasBookMarked.error){
 325→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 326→        }
 327→        hasLikedResult = hasLiked.data || [];
 328→        hasBookMarkedResult = hasBookMarked.data || [];
 329→    }
 330→
 331→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 332→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 333→
 334→    const formatted = merged.map((notif) => ({
 335→        ...notif,
 336→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 337→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 338→    }))
 339→
 340→    const hasMore = formatted.length > parseInt(limit);
 341→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 342→
 343→    return res.status(200).json(
 344→        {
 345→            hasMore: hasMore,
 346→            data: slicedData,
 347→        }
 348→    )
 349→
 350→})
