 389→        users!sender_id(name, user_email, image_url, id, badge)
 390→        `)
 391→    .eq('receiver_id', receiverId)
 392→    .eq('read', false)
 393→    .order('created_at', {ascending: false})
 394→    .order('id', {ascending: false})
 395→    .limit(fetchLimit)
