   9→const PROFILE_MEDIA_BUCKETS = ['background', 'journal-images', 'avatars'];
  10→const PROFILE_MEDIA_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp', '.avif', '.svg'];
  11→const PROFILE_MEDIA_LIMIT_DEFAULT = 5;
