  24→const attachUserInteractionFlags = async (journals, userId) => {
  25→    if(!Array.isArray(journals) || journals.length === 0){
  26→        return [];
  27→    }
  28→
  29→    if(!userId){
  30→        return journals.map((journal) => ({
  31→            ...journal,
  32→            has_liked: false,
  33→            has_bookmarked: false
  34→        }));
  35→    }
  36→
  37→    const journalIds = journals.map((journal) => journal.id);
  38→
  39→    const [userLikes, userBookmarks] = await Promise.all([
  40→        supabase
  41→            .from('likes')
  42→            .select('journal_id')
  43→            .in('journal_id', journalIds)
  44→            .eq('user_id', userId),
  45→        supabase
  46→            .from('bookmarks')
  47→            .select('journal_id')
  48→            .in('journal_id', journalIds)
  49→            .eq('user_id', userId)
  50→    ]);
  51→
  52→    const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
  53→    const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
  54→
  55→    if(errorUserLikeResult || errorUserBookmarksResult){
  56→        console.error('supabase error while fetching journal interactions:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
  57→        throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'};
  58→    }
  59→
  60→    const userHasLikedSet = new Set(userLikesResult?.map((journal) => journal.journal_id) || []);
  61→    const userHasBookmarkedSet = new Set(userBookmarksResult?.map((journal) => journal.journal_id) || []);
  62→
  63→    return journals.map((journal) => ({
  64→        ...journal,
  65→        has_liked: userHasLikedSet.has(journal.id),
  66→        has_bookmarked: userHasBookmarkedSet.has(journal.id)
  67→    }));
