  70→const hasSupportedMediaExtension = (fileName = '') => {
  71→    const lowerFileName = fileName.toLowerCase();
  72→    return PROFILE_MEDIA_EXTENSIONS.some((ext) => lowerFileName.endsWith(ext));
  73→};
  74→
  75→const parseMediaTimestamp = (item = {}) => {
  76→    const fileName = item?.name || '';
  77→    const timestampPrefix = fileName.match(/^(\d+)_/);
  78→
  79→    if(timestampPrefix?.[1]){
  80→        const parsedPrefix = Number(timestampPrefix[1]);
  81→        if(!Number.isNaN(parsedPrefix)){
  82→            return parsedPrefix;
  83→        }
  84→    }
  85→
  86→    const parsedDate = Date.parse(item?.created_at || item?.updated_at || '');
  87→    return Number.isNaN(parsedDate) ? 0 : parsedDate;
  88→};
  89→
  90→const createInitialMediaCursorState = () => ({
  91→    offsets: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, 0])),
  92→    exhausted: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, false])),
  93→    pending: []
  94→});
  95→
  96→const parseMediaCursor = (cursor) => {
  97→    if(!cursor){
  98→        return createInitialMediaCursorState();
  99→    }
 100→
 101→    try {
 102→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 103→        const parsed = JSON.parse(decoded);
 104→        const initial = createInitialMediaCursorState();
 105→
 106→        if(parsed?.offsets && typeof parsed.offsets === 'object'){
 107→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 108→                const value = Number(parsed.offsets[bucket]);
 109→                initial.offsets[bucket] = Number.isNaN(value) || value < 0 ? 0 : value;
 110→            });
 111→        }
 112→
 113→        if(parsed?.exhausted && typeof parsed.exhausted === 'object'){
 114→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 115→                initial.exhausted[bucket] = Boolean(parsed.exhausted[bucket]);
 116→            });
 117→        }
 118→
 119→        if(Array.isArray(parsed?.pending)){
 120→            initial.pending = parsed.pending
 121→                .filter((item) => PROFILE_MEDIA_BUCKETS.includes(item?.bucket) && typeof item?.path === 'string' && typeof item?.name === 'string')
 122→                .map((item) => ({
 123→                    bucket: item.bucket,
 124→                    path: item.path,
 125→                    name: item.name,
 126→                    createdAt: item.createdAt || null,
 127→                    timestamp: Number(item.timestamp) || 0
 128→                }));
 129→        }
 130→
 131→        return initial;
 132→    } catch {
 133→        return createInitialMediaCursorState();
 134→    }
 135→};
