 142→const parseCanvasGalleryCursor = (cursor, expectedSort = 'hottest') => {
 143→    const fallback = {
 144→        offset: 0,
 145→        sort: expectedSort
 146→    };
 147→
 148→    if(!cursor){
 149→        return fallback;
 150→    }
 151→
 152→    try {
 153→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 154→        const parsed = JSON.parse(decoded);
 155→        const parsedSort = typeof parsed?.sort === 'string' && parsed.sort.toLowerCase().trim() === 'newest'
 156→            ? 'newest'
 157→            : 'hottest';
 158→
 159→        if(parsedSort !== expectedSort){
 160→            return fallback;
 161→        }
 162→
 163→        const parsedOffset = Number(parsed?.offset);
 164→        const normalizedOffset = Number.isNaN(parsedOffset) || parsedOffset < 0
 165→            ? 0
 166→            : Math.floor(parsedOffset);
 167→
 168→        return {
 169→            offset: normalizedOffset,
 170→            sort: parsedSort
 171→        };
 172→    } catch {
 173→        return fallback;
 174→    }
 175→};
 176→
 177→const encodeCanvasGalleryCursor = (offset, sort) => {
 178→    const payload = JSON.stringify({
 179→        offset: offset,
 180→        sort: sort
 181→    });
 182→    return Buffer.from(payload, 'utf8').toString('base64');
 183→};
