 955→        bookmark_count: bookmarks(count),
 956→
 957→        users(name, user_email, image_url, badge),
 958→
 959→        like_count: likes(count)
 960→        )
 961→        `, {count: 'exact'})
 962→
 963→    .eq('user_id', userId)
 964→    .order('created_at', {ascending: false})
 965→    .order('id', {ascending: false})
 966→    .limit(parseInt(limit) + 1)
 967→
 968→    if(before){
 969→        query = query.lt('created_at', before);
 970→    }
 971→
 972→    const {data: bookMarksData, error: errorBookmarks, count} = await query;
 973→
 974→    if(errorBookmarks){
 975→        console.error('supabase error:', errorBookmarks.message);
 976→        throw {status: 500, error: 'supabase error while fetching bookmarks'}
 977→    }
 978→
 979→    const journalIds = bookMarksData?.map((bookmark) => bookmark.journals.id);
 980→
 981→    if(journalIds.length === 0){
 982→        return {data: [], hasMore: false}
 983→    }
 984→
 985→    let hasLikedPromise;
 986→    let hasBookmarkedPromise;
 987→
 988→    if(journalIds){
 989→        hasLikedPromise = supabase
 990→        .from('likes')
 991→        .select('journal_id')
 992→        .in('journal_id', journalIds)
 993→        .eq('user_id', userId)
 994→
 995→        hasBookmarkedPromise = supabase
 996→        .from('bookmarks')
 997→        .select('journal_id')
 998→        .in('journal_id', journalIds)
 999→        .eq('user_id', userId)
1000→    }
1001→
1002→    const [hasLiked, hasBookMarked] = await Promise.all([
1003→        hasLikedPromise, hasBookmarkedPromise
1004→    ])
1005→
1006→    const {data: hasLikedResult, error: errorHasLikedResult} = hasLiked;
1007→    const {data: hasBookMarkedResult, error: errorHasbookmarkedResult} = hasBookMarked;
1008→
1009→    if(errorHasLikedResult || errorHasbookmarkedResult){
1010→        console.error('supabase error while fetching data:', errorHasLikedResult.message || errorHasbookmarkedResult.message);
1011→        throw {status: 500, error: 'supabase error while fetching data'};
1012→    }
1013→    
1014→    const userHasLikedSet = new Set(hasLikedResult.map((journal) => journal.journal_id) || []);
1015→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id) || []);
1016→
1017→    const hasMore = bookMarksData.length > paresedLimit;
1018→
1019→
1020→    const formattedData = bookMarksData.map((b) => ({
1021→        ...b,
1022→        has_liked: userHasLikedSet.has(b.journals.id),
1023→        has_bookmarked: userHasBookmarkedSet.has(b.journals.id),
1024→    }))
1025→
1026→    const slicedData = hasMore ? formattedData.splice(0, paresedLimit) : formattedData;
1027→
1028→    return {
1029→        bookmarks: slicedData,
1030→        hasMore: hasMore,
1031→        totalBookmarks: before ? null : count
1032→    }
1033→}
