 19→const parseCanvasDocInput = (canvasDoc) => {
 20→    if(!canvasDoc){
 21→        return null;
 22→    }
 23→
 24→    const parsedCanvasDoc = typeof canvasDoc === 'string' ? JSON.parse(canvasDoc) : canvasDoc;
 25→    if(!parsedCanvasDoc || typeof parsedCanvasDoc !== 'object'){
 26→        throw new Error('canvas_doc should be a valid object');
 27→    }
 28→
 29→    if(!Array.isArray(parsedCanvasDoc.snippets)){
 30→        throw new Error('canvas_doc.snippets should be an array');
 31→    }
 32→
 33→    return parsedCanvasDoc;
 34→}
 35→
 36→const extractCanvasPlainText = (canvasDoc) => {
 37→    if(!canvasDoc || !Array.isArray(canvasDoc.snippets)){
 38→        return '';
 39→    }
 40→
 41→    return canvasDoc.snippets
 42→        .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text.trim() : ''))
 43→        .filter(Boolean)
 44→        .join(' ');
 45→}
