 47→const parseTextContentSafely = (content) => {
 48→    if(typeof content !== 'string' || !content.trim()){
 49→        return null;
 50→    }
 51→
 52→    const parsedData = ParseContent(content);
 53→    if(!parsedData || typeof parsedData !== 'object'){
 54→        return null;
 55→    }
 56→
 57→    return parsedData;
 58→}
