 12→const normalizeStampPayload = (stamp) => ({
 13→    id: stamp?.id,
 14→    journal_id: stamp?.journal_id,
 15→    user_id: stamp?.user_id,
 16→    snippet_id: stamp?.snippet_id,
 17→    word_key: stamp?.word_key,
 18→    stamp_type: stamp?.stamp_type,
 19→    x: stamp?.x,
 20→    y: stamp?.y,
 21→    created_at: stamp?.created_at,
 22→    user_name: stamp?.users?.name || null,
 23→    user_image_url: stamp?.users?.image_url || null
 24→});
 25→
 26→const normalizeMarginPayload = (item) => ({
 27→    id: item?.id,
 28→    journal_id: item?.journal_id,
 29→    user_id: item?.user_id,
 30→    item_type: item?.item_type,
 31→    payload: item?.payload || null,
 32→    created_at: item?.created_at,
 33→    updated_at: item?.updated_at,
 34→    user_name: item?.users?.name || null,
 35→    user_image_url: item?.users?.image_url || null
 36→});
