150→export const addCanvasStampService = async({journalId, userId, snippetId, wordKey, stampType, x, y}) => {
151→    if(!userId){
152→        throw {status: 401, error: 'userId is undefined'};
153→    }
154→
155→    await assertCanvasJournalAccess(journalId, userId);
156→
157→    if(!snippetId || typeof snippetId !== 'string'){
158→        throw {status: 400, error: 'snippetId should be a string'};
159→    }
160→
161→    const normalizedStampType = typeof stampType === 'string' ? stampType.trim().toLowerCase() : '';
162→    if(!ALLOWED_STAMP_TYPES.has(normalizedStampType)){
163→        throw {status: 400, error: 'invalid stamp_type'};
164→    }
165→
166→    const normalizedX = parseNumberInRange(x, 'x');
167→    const normalizedY = parseNumberInRange(y, 'y');
168→    const normalizedWordKey = typeof wordKey === 'string' && wordKey.trim() ? wordKey.trim().slice(0, 128) : null;
169→
170→    const insertPayload = {
171→        journal_id: journalId,
172→        user_id: userId,
173→        snippet_id: snippetId.trim(),
174→        word_key: normalizedWordKey,
175→        stamp_type: normalizedStampType,
176→        x: normalizedX,
177→        y: normalizedY
178→    };
179→
180→    const {data: insertedStamp, error: insertError} = await supabase
181→    .from('canvas_stamps')
182→    .insert(insertPayload)
183→    .select(STAMP_SELECT)
184→    .single();
185→
186→    if(insertError){
187→        const isDuplicateStamp =
188→            insertError?.code === '23505' ||
189→            (insertError?.message || '').includes('uq_canvas_stamps_user_target_type');
190→
191→        if(isDuplicateStamp){
192→            let existingStampQuery = supabase
193→            .from('canvas_stamps')
194→            .select(STAMP_SELECT)
195→            .eq('journal_id', journalId)
196→            .eq('user_id', userId)
197→            .eq('snippet_id', snippetId.trim())
198→            .eq('stamp_type', normalizedStampType);
199→
200→            existingStampQuery = normalizedWordKey
201→                ? existingStampQuery.eq('word_key', normalizedWordKey)
202→                : existingStampQuery.is('word_key', null);
203→
204→            let {data: existingStamp, error: existingStampError} = await existingStampQuery.maybeSingle();
205→            if(existingStampError){
206→                console.error('supabase error while fetching duplicate canvas stamp:', existingStampError.message);
207→                throw {status: 500, error: 'supabase error while adding canvas stamp'};
208→            }
209→
210→            if(!existingStamp?.id){
211→                const {data: fallbackStamps, error: fallbackError} = await supabase
212→                .from('canvas_stamps')
213→                .select(STAMP_SELECT)
214→                .eq('journal_id', journalId)
215→                .eq('user_id', userId)
216→                .eq('snippet_id', snippetId.trim())
217→                .eq('stamp_type', normalizedStampType)
218→                .order('created_at', {ascending: false})
219→                .limit(1);
220→
221→                if(fallbackError){
222→                    console.error('supabase error while resolving duplicate canvas stamp:', fallbackError.message);
223→                    throw {status: 500, error: 'supabase error while adding canvas stamp'};
224→                }
225→
226→                existingStamp = Array.isArray(fallbackStamps) ? fallbackStamps[0] : null;
227→            }
228→
229→            if(!existingStamp?.id){
230→                throw {status: 409, error: 'duplicate stamp exists'};
231→            }
232→
233→            const {data: updatedStamp, error: updateError} = await supabase
234→            .from('canvas_stamps')
235→            .update({
236→                x: normalizedX,
237→                y: normalizedY
238→            })
239→            .eq('id', existingStamp.id)
240→            .select(STAMP_SELECT)
241→            .single();
242→
243→            if(updateError){
244→                console.error('supabase error while updating duplicate canvas stamp:', updateError.message);
245→                throw {status: 500, error: 'supabase error while adding canvas stamp'};
246→            }
247→
248→            return normalizeStampPayload(updatedStamp);
249→        }
250→
251→        console.error('supabase error while adding canvas stamp:', insertError.message);
252→        throw {status: 500, error: 'supabase error while adding canvas stamp'};
253→    }
254→
255→    return normalizeStampPayload(insertedStamp);
256→}
